// Prospecting intelligence brief for a target account
return [{ json: {
  account_name: 'Twitch Interactive',
  opportunity_hint: 'New Business'
}}];

// Parse find_account response, extract account_id and select the right opportunity
const raw = $json;
const target = $('Set Target').first().json;

let payload = raw;
if (raw.content && Array.isArray(raw.content) && raw.content[0]) {
  const t = raw.content[0].text;
  payload = (typeof t === 'string') ? JSON.parse(t) : t;
}

const accountId = payload?.peopleai_account_id;
const accountName = payload?.name;
const opportunities = payload?.opportunities || [];

if (!accountId) {
  throw new Error(`Could not resolve account ID for "${target.account_name}". find_account returned: ${JSON.stringify(payload).slice(0,300)}`);
}
if (opportunities.length === 0) {
  throw new Error(`No opportunities found for account "${accountName}".`);
}

let selectedOpp;
const hint = (target.opportunity_hint || '').toLowerCase().trim();
if (hint) {
  selectedOpp = opportunities.find(o => (o.opportunity_name || '').toLowerCase().includes(hint));
}
if (!selectedOpp) {
  selectedOpp = [...opportunities].sort((a, b) => (b.engagement_level || 0) - (a.engagement_level || 0))[0];
}

return [{ json: {
  peopleai_account_id: accountId,
  peopleai_opportunity_id: selectedOpp.peopleai_opportunity_id,
  account_name: accountName,
  account_domain: payload?.domain,
  opportunity_name: selectedOpp.opportunity_name,
  opportunity_amount: selectedOpp.amount,
  opportunity_close_date: selectedOpp.close_date,
  opportunity_engagement_level: selectedOpp.engagement_level,
  opportunity_owner: selectedOpp.owner?.name,
  opportunity_type: selectedOpp.type,
  all_opportunities: opportunities.map(o => ({ id: o.peopleai_opportunity_id, name: o.opportunity_name })),
  ...target
} }];

// Bulletproof merge: always returns strings, never [object Object]
function extractText(nodeName) {
  try {
    const item = $(nodeName).first();
    if (!item || !item.json) return '(no data returned)';
    const raw = item.json;
    let payload = raw;
    if (raw.content && Array.isArray(raw.content) && raw.content[0]) {
      payload = raw.content[0].text !== undefined ? raw.content[0].text : raw.content[0];
    } else if (Array.isArray(raw) && raw[0]) {
      payload = raw[0].text !== undefined ? raw[0].text : raw[0];
    }
    if (typeof payload === 'string') {
      const trimmed = payload.trim();
      if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
        try { return JSON.stringify(JSON.parse(trimmed), null, 2); } catch(e) { return payload; }
      }
      return payload;
    }
    return JSON.stringify(payload, null, 2);
  } catch(e) {
    return `(extraction error: ${e.message})`;
  }
}

const resolved = $('Resolve IDs').first().json;
return [{ json: {
  opportunityName: resolved.opportunity_name,
  accountName: resolved.account_name,
  opportunityOwner: resolved.opportunity_owner,
  opportunityAmount: resolved.opportunity_amount,
  opportunityCloseDate: resolved.opportunity_close_date,
  // pass-through user-set fields
  ...$('Set Target').first().json,
  accountStatus: extractText('Get Account Status'),
  recentActivity: extractText('Get Recent Account Activity'),
  situationSearch: extractText('Situation Search'),
} }];

const j = $json;

const prompt = `You are a prospecting intelligence assistant helping a rep prioritize and personalize outbound.

Prospect Account: ${j.accountName}
Anchor Opportunity: ${j.opportunityName || 'None'} | Owner: ${j.opportunityOwner || 'TBD'}

## Account Status & Signals
${j.accountStatus}

## Recent Account Activity
${j.recentActivity}

## Similar Companies That Became Customers (Situation Search)
${j.situationSearch}

Produce a prospecting brief as Slack mrkdwn:

:rocket: *Prospecting Brief — ${j.accountName}*

*Engagement Signal* — current momentum (buying signals, cold, unknown). Be specific.

*ICP Fit & Whitespace* — what makes this a good fit, where the opportunity is

*Comparable Companies That Bought* — 2-3 examples: what stage triggered the deal, outcome

*Recommended Play* — based on the comparables, what approach should the rep take?

*Talking Points* — 3 specific, evidence-based talking points for the first call

Under 350 words. Be specific and actionable. Slack mrkdwn (*bold*, • bullets).`;

return [{ json: { ...j, prompt } }];
